<?php
 declare(strict_types=1); namespace tapmeppe\composer\summons; use tapmeppe\composer\blueprint\Resources; use tapmeppe\composer\helpers\Abcd; class AbcdViewsExtension extends \Illuminate\Console\Command { protected $signature = 'governance:abcd:views-extension'; protected $description = 'Add the blade components of the governance⚙️ extension to the views.'; public function handle() { $components = ['head' => 'head', 'foot' => 'body',]; $errors = 0; $folders = []; $root = dirname(__DIR__, 4); switch (Abcd::getTool()) { case 'accounting': case 'laravel': $folders = [ 'resources/views' => [ 'email/', 'vendor/', ], ]; break; case 'contacts': $folders = [ 'packages/Webkul/Admin/src/Resources/views' => [], 'packages/Webkul/Installer/src/Resources/views' => [], 'packages/Webkul/WebForm/src/Resources/views' => [], ]; break; } foreach ($folders as $folder => $flags) { $this->info("Processing folder '$folder' ..."); Resources::listRecursive( $directory = "$root/$folder", function ($name, $path) use ($components, $directory, &$errors, $flags) { if (str_ends_with($name, '.blade.php')) { $prefix = str_replace("$directory/", '', $path); foreach ($flags as $flag) if (str_starts_with($prefix, $flag)) return; $content = Resources::read($path); foreach ($components as $key => $tag) { $component = "<x-governance-$key/>"; $tag = "</$tag>"; $message = "- $prefix > $key"; if (str_contains($content, $component) || !str_contains($content, $tag)) continue; elseif (Resources::write($path, $content = str_replace($tag, $component . $tag, $content))) $this->info("$message-added"); else { $this->info("$message-FAILED"); $errors++; } } } } ); } $this->info("Done. $errors errors."); exit($errors); } } 